/// <summary>
/// Enables/disables some button on form <c>DirPartyTable</c>.
/// </summary>
/// <param name="_args">The <c>DirPartyTable</c> formrun.</param>
[PostHandlerFor(formStr(DirPartyTable), formMethodStr(DirPartyTable, updateControls))]
public static void DirPartyTable_Post_updateControls(XppPrePostArgs _args)
{
    FormRun                     form = _args.getThis();
    FormDataSource              dirPartyTable_ds  = form.dataSource(formdatasourcestr(DirPartyTable, DirPartyTable)) as FormDataSource;
    FormFunctionButtonControl   buttonFWFTextBlockUsageEx = form.design().controlName(formControlStr(DirPartyTable, FWFTextBlockUsageEx_GAB));

    buttonFWFTextBlockUsageEx.enabled(DirPartyTableHelper::isCustomer(dirPartyTable_ds.cursor().RecId) || DirPartyTableHelper::isvendor(dirPartyTable_ds.cursor().RecId));
}

    /// <param name="sender"></param>
    /// <param name="e"></param>
    [FormDataFieldEventHandler(formDataFieldStr(ReqGroup, ReqGroup, CovRule), FormDataFieldEventType::Modified),
	SuppressBPWarning('BPParameterNotUsed', 'Parameter required by the event interface.')]
    public static void CovRule_OnModified(FormDataObject _sender, FormDataFieldEventArgs _e)
    {
        FormDatasource	reqGroupDS = _sender.datasource();
        ReqGroup		reqGroup	= reqGroupDS.cursor() as ReqGroup;

        if (reqGroup.CovRule == ReqCovType::Req)
        {
            reqGroupDS.object(fieldNum(ReqGroup, FWFTextBlockCopyFromSalesOrder)).enabled(true);
        }
		else
        {
            reqGroup.FWFTextBlockCopyFromSalesOrder = NoYes::No;
            reqGroupDS.object(fieldNum(ReqGroup, FWFTextBlockCopyFromSalesOrder)).enabled(false);
        }

    }

    /// <summary>
    ///
    /// </summary>
    /// <param name="sender"></param>
    /// <param name="e"></param>
    [FormDataSourceEventHandler(formDataSourceStr(ReqGroup, ReqGroup), FormDataSourceEventType::Activated),
	SuppressBPWarning('BPParameterNotUsed', 'Parameter required by the event interface.')]
    public static void ReqGroup_OnActivated(FormDataSource _sender, FormDataSourceEventArgs _e)
    {
        ReqGroup reqGroup = _sender.cursor() as ReqGroup;

        if (reqGroup.CovRule == ReqCovType::Req)
        {
            _sender.object(fieldNum(ReqGroup, FWFTextBlockCopyFromSalesOrder)).enabled(true);
        }
        else
        {
            _sender.object(fieldNum(ReqGroup, FWFTextBlockCopyFromSalesOrder)).enabled(false);
        }

    }
